import{_ as e,c as t,o as a,a4 as i}from"./chunks/framework.ttppV29E.js";const n="/assets/editor.D71iz54D.png",s="/assets/diagram.CngnpG4h.png",o="/assets/workflow.B66m3qeS.png",k=JSON.parse('{"title":"Transition Sets","description":"","frontmatter":{},"headers":[],"relativePath":"docs/transition-sets/index.md","filePath":"docs/transition-sets/index.md","lastUpdated":1775835030000}'),r={name:"docs/transition-sets/index.md"},l=i('<h1 id="transition-sets" tabindex="-1">Transition Sets <a class="header-anchor" href="#transition-sets" aria-label="Permalink to &quot;Transition Sets&quot;">​</a></h1><div class="info custom-block github-alert"><p class="custom-block-title">INFO</p><p>Transition sets will be released in version 2.38.0</p></div><p>Transition Sets allow you to define and control how tasks can move between statuses. They let you configure which statuses can be used for a task, and what the transitions between statuses should be called.</p><h2 id="managing-transition-sets" tabindex="-1">Managing Transition Sets <a class="header-anchor" href="#managing-transition-sets" aria-label="Permalink to &quot;Managing Transition Sets&quot;">​</a></h2><p>If you have permission to manage transition sets, you will be able to access the <strong>Transition Sets</strong> page from the side menu. From there you can:</p><ul><li>Create a new blank transition set</li><li>Duplicate an existing transition set <ul><li>This will create a new transition set pre-populated with the transitions from another set</li></ul></li><li>Edit or delete existing transition sets</li><li>View the default transition sets</li><li>View a diagram of any transition set</li><li>Export a transition set</li></ul><h3 id="configuring-a-set" tabindex="-1">Configuring a Set <a class="header-anchor" href="#configuring-a-set" aria-label="Permalink to &quot;Configuring a Set&quot;">​</a></h3><p><img src="'+n+'" alt="Transition Sets editor"> In this image of the Transition Sets editor, you can see an example set containing a single transition from <code>New</code> to <code>Cancelled</code>. The status of a task using this transition set could be changed from <code>New</code> to <code>Cancelled</code>, and then it could not be changed again, because there are no transitions out of the <code>Cancelled</code> status.</p><p>Because the <strong>Prevent Manual Transitions</strong> toggle is off, this status change would be allowed via the AireFrame UI and Aireflow&#39;s UI and API. It would also be allowed via mutations regardless of this toggle.</p><p><img src="'+s+'" alt="Transition Set diagram"> Here you can see the diagram of the example set created above.</p><h3 id="git-integration" tabindex="-1">Git Integration <a class="header-anchor" href="#git-integration" aria-label="Permalink to &quot;Git Integration&quot;">​</a></h3><ul><li>Transition sets can be stored and in your Git repositories, in a folder called <code>TransitionSets</code></li></ul><h2 id="using-transition-sets" tabindex="-1">Using Transition Sets <a class="header-anchor" href="#using-transition-sets" aria-label="Permalink to &quot;Using Transition Sets&quot;">​</a></h2><h3 id="assign-to-task-definitions" tabindex="-1">Assign to Task Definitions <a class="header-anchor" href="#assign-to-task-definitions" aria-label="Permalink to &quot;Assign to Task Definitions&quot;">​</a></h3><ul><li>You can specify a transition set when defining a task <img src="'+o+'" alt="Transition Set in workflow"></li><li>This controls the allowed transitions for all tasks created from that definition</li></ul><h3 id="task-behavior" tabindex="-1">Task Behavior <a class="header-anchor" href="#task-behavior" aria-label="Permalink to &quot;Task Behavior&quot;">​</a></h3><p>If a task has a transition set:</p><ul><li>Only transitions from that set are allowed</li></ul><p>If no transition set is specified:</p><ul><li>A default transition set is used (depending on the type of the task) to ensures backwards compatibility</li><li>The <code>default</code>, <code>default-form</code> &amp; <code>default-automated</code> sets can be seen (but not edited) on the Transition Sets page.</li></ul><h2 id="aireframe-integration" tabindex="-1">AireFrame Integration <a class="header-anchor" href="#aireframe-integration" aria-label="Permalink to &quot;AireFrame Integration&quot;">​</a></h2><ul><li>For tasks in AireFrame, only the allowed transitions will be shown</li><li>The description you set for each transition will be shown in the task&#39;s action menu</li></ul><h2 id="checking-available-transitions" tabindex="-1">Checking Available Transitions <a class="header-anchor" href="#checking-available-transitions" aria-label="Permalink to &quot;Checking Available Transitions&quot;">​</a></h2><p>The <code>transitions</code> property on the graphQL tasks API will return whichever transitions are possible, dependent on a task&#39;s current status.</p>',24),d=[l];function c(h,u,g,f,p,m){return a(),t("div",null,d)}const T=e(r,[["render",c]]);export{k as __pageData,T as default};
